import urllib.request
import json
import ssl
ssl._create_default_https_context = ssl._create_unverified_context

url = 'https://data.ecb.europa.eu/data/geographical-areas/georgia?format=json'
req = urllib.request.Request(url, headers={'User-Agent': 'Mozilla/5.0'})
resp = urllib.request.urlopen(req, timeout=15)
data = json.loads(resp.read())
print("Top keys:", list(data.keys()))
if 'data' in data:
    print("Data type:", type(data['data']))
    if isinstance(data['data'], dict):
        # Explore structure
        for k in list(data['data'].keys())[:5]:
            print(f"  Key: {k}")
            if isinstance(data['data'][k], dict):
                for k2 in list(data['data'][k].keys())[:10]:
                    print(f"    {k2}")
elif 'series' in data:
    print("Series keys:", list(data['series'].keys())[:10])
elif '_links' in data:
    print("_links:", json.dumps(data['_links'], indent=2)[:1000])
else:
    # Print first 3 top-level items
    for key in list(data.keys())[:3]:
        print(f"{key}: {type(data[key])} -> {json.dumps(data[key])[:500]}")
