import openpyxl
wb = openpyxl.load_workbook('/root/pwt100.xlsx', data_only=True)
ws = wb['Data']
# Find column indices for needed variables
col_map = {}
for c in range(1, ws.max_column+1):
    h = ws.cell(row=1, column=c).value
    if h:
        col_map[h] = c
print("Column mapping:")
for k,v in col_map.items():
    print(f"  {k}: col {v}")

# Extract Georgia data for key variables
vars_of_interest = ['rnna', 'rgdpna', 'delta', 'labsh', 'rdana', 'cn', 'ck', 'cgdpe']
print("\nGeorgia data:")
for row in range(2, ws.max_row+1):
    if ws.cell(row=row, column=1).value == 'GEO':
        year = ws.cell(row=row, column=4).value
        vals = {}
        for var in vars_of_interest:
            if var in col_map:
                vals[var] = ws.cell(row=row, column=col_map[var]).value
        print(f"Year {year}: {vals}")
EOF
